// ✅ 테마 0번 (도서관) 기본 배경 이미지 - Base64 (약 920KB)
// 이 상수를 삭제하면 JavaScript 책꽂이 폴백으로 표시됨
define('THEME_0_DEFAULT_BG', '');


// ✅ LOGIN_PAGE 상수 정의 (init.php에서 로그인 체크 건너뜀)
define('LOGIN_PAGE', true);

if (!headers_sent()) { ob_start(); }
session_cache_limiter('nocache');
header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');
header('Pragma: no-cache');
header('Expires: 0');

// ✅ bootstrap.php 사용으로 통일 (config → init → function → security_helpers 순차 로드)
require_once __DIR__ . '/bootstrap.php';

// ✅ IP 차단 및 브루트포스 방지
require_once __DIR__ . '/ip_block.php';
$ipBlocker = new IPBlocker();

// 브루트포스 체크 (로그인 시도 전)
$bruteforceCheck = $ipBlocker->checkBruteforce();
if ($bruteforceCheck['blocked']) {
    $ipBlocker->showBruteForcePage($bruteforceCheck['remaining']);
}

// ✅ bidx 파라미터 처리 (init_bidx 사용)
// $bidx_query, $bidx_param 등 전역 변수도 함께 설정됨
$bidx = init_bidx();

// ✅ 폴더 이름 추출 함수
function get_folder_name($path) {
    return basename(rtrim($path, '/\\'));
}

function load_login_theme() {
    $f = "./src/login_theme.json";
    if (!file_exists($f)) return ['theme' => 0, 'backgrounds' => [], 'filters' => []];
    $d = json_decode(file_get_contents($f), true);
    return [
        'theme' => (int)($d['theme'] ?? 0),
        'backgrounds' => $d['backgrounds'] ?? [],
        'filters' => $d['filters'] ?? []
    ];
}

// ✅ 로그인 유지 토큰 함수들은 security_helpers.php에서 통합 제공
// 함수: get_remember_tokens_file(), load_remember_tokens(), save_remember_tokens(),
//       get_device_hash(), generate_remember_token(), create_remember_token(),
//       verify_remember_token(), delete_remember_token(), delete_user_remember_tokens()

// ✅ 로고 HTML 출력
function render_login_logo($branding) {
    if (($branding['logo_type'] ?? 'text') === 'image' && !empty($branding['logo_image']) && file_exists($branding['logo_image'])) {
        return '<img src="' . h($branding['logo_image']) . '" alt="' . h($branding['logo_text']) . '" style="max-height:1.8em; max-width:100%;">';
    }
    return h($branding['logo_text'] ?? __('branding_default_logo'));
}

// ✅ 아이디찾기/비밀번호찾기/회원가입 링크 출력
function render_find_links($find_id_enabled, $find_password_enabled, $registration_enabled) {
    $links = [];
    if ($find_id_enabled) {
        $links[] = '<a href="login.php?mode=find_id">' . __h('find_id') . '</a>';
    }
    if ($find_password_enabled) {
        $links[] = '<a href="login.php?mode=find_password">' . __h('find_password') . '</a>';
    }
    
    $html = '';
    if (!empty($links)) {
        $html .= '<div class="find-links">' . implode('<span>|</span>', $links) . '</div>';
    }
    
    // 회원가입은 별도로 표시
    if ($registration_enabled) {
        $html .= '<div class="signup-link">' . __h('signup_no_account') . ' <a href="login.php?mode=signup">' . __h('signup') . '</a></div>';
    }
    
    return $html;
}

function clearUserCache($user_id, $base = __DIR__ . "/cache") {
    $safe_id = preg_replace('/[^a-zA-Z0-9_]/', '', $user_id);
    $user_dir = $base . "/" . $safe_id;
    if (!is_dir($user_dir)) return;
    foreach (glob("$user_dir/*") as $zip_dir) {
        if (is_dir($zip_dir)) {
            foreach (glob("$zip_dir/*") as $file) { @unlink($file); }
            @rmdir($zip_dir);
        } else { @unlink($zip_dir); }
    }
    @rmdir($user_dir);
}

function validateUserId($id) { return preg_match('/^[a-zA-Z0-9_]{3,20}$/', $id); }
function validatePassword($pass) { return strlen($pass) >= 8; }

// ✅ 로그인 유지 토큰이 있으면 자동 로그인 후 index.php로 이동
// (timeout으로 왔어도 토큰이 유효하면 자동 로그인)
if (empty($_SESSION['user_id']) && isset($_COOKIE['remember_token'])) {
    $token = $_COOKIE['remember_token'];
    $user_id = verify_remember_token($token);
    
    if ($user_id) {
        $users = load_users();
        if (isset($users[$user_id])) {
            $user = $users[$user_id];
            
            // ✅ 사용자 상태 체크 (정지/대기 상태이면 자동 로그인 불가)
            $user_status = $user['status'] ?? 'active';
            if ($user_status === 'pending') {
                // 대기 상태 - 토큰 삭제하고 로그인 페이지로
                delete_remember_token($token);
                setcookie('remember_token', '', time() - 3600, '/');
                $_SESSION['login_error'] = __('login_error_pending');
                header("Location: login.php");
                exit;
            }
            if ($user_status === 'suspended') {
                // 정지 상태 - 정지 기간 체크
                $suspend_end = $user['suspend_end'] ?? null;
                if ($suspend_end) {
                    $end_date = strtotime($suspend_end);
                    if ($end_date && $end_date > time()) {
                        // 아직 정지 기간
                        delete_remember_token($token);
                        setcookie('remember_token', '', time() - 3600, '/');
                        $_SESSION['login_error'] = __('login_error_suspended', date('Y-m-d', $end_date));
                        header("Location: login.php");
                        exit;
                    } else {
                        // 정지 기간 만료 - 자동 해제
                        $users[$user_id]['status'] = 'active';
                        $users[$user_id]['suspend_reason'] = null;
                        $users[$user_id]['suspend_start'] = null;
                        $users[$user_id]['suspend_end'] = null;
                        save_users($users);
                        $user = $users[$user_id];
                    }
                }
            }
            
            // 자동 로그인 성공
            $ipBlocker->clearLoginAttempts(); // 브루트포스 기록 초기화
            $_SESSION['user_id'] = $user_id;
            $_SESSION['user_pass'] = '';
            $_SESSION['user_group'] = $user['group'] ?? 'group2';
            $_SESSION['last_action'] = time();
            $_SESSION['auto_login'] = true;
            $_SESSION['remember_me'] = true;
            
            // ✅ 캐시 갱신 플래그 초기화 (새 콘텐츠 반영을 위해)
            unset($_SESSION['index_refreshed']);
            unset($_SESSION['zip_cache_generated']);
            unset($_SESSION['filelist_cache_generated']);
            
            // timeout 메시지 제거 (자동 로그인되었으므로)
            unset($_SESSION['timeout_message']);
            unset($_SESSION['login_error']);
            
            header("Location: index.php" . $bidx_query);
            exit;
        }
    }
}

// POST: 사용자 생성
if (isset($_POST['mode']) && $_POST['mode'] === "make_id") {
    $id = trim($_POST['id'] ?? '');
    $pass = $_POST['pass'] ?? '';
    $email = trim($_POST['email'] ?? '');
    $group = $_POST['group'] ?? 'group2';
    
    if (!validateUserId($id)) {
        echo "<div style='padding:50px;text-align:center;'><div style='background:#f8d7da;color:#721c24;padding:20px;border-radius:10px;max-width:400px;margin:0 auto;'>" . __h('setup_id_error') . "</div></div>";
        echo "<meta http-equiv='refresh' content='3; url=login.php?mode=adduser'>";
        exit;
    }
    if (!validatePassword($pass)) {
        echo "<div style='padding:50px;text-align:center;'><div style='background:#f8d7da;color:#721c24;padding:20px;border-radius:10px;max-width:400px;margin:0 auto;'>" . __h('setup_password_error') . "</div></div>";
        echo "<meta http-equiv='refresh' content='3; url=login.php?mode=adduser'>";
        exit;
    }
    if (!empty($email) && !filter_var($email, FILTER_VALIDATE_EMAIL)) {
        echo "<div style='padding:50px;text-align:center;'><div style='background:#f8d7da;color:#721c24;padding:20px;border-radius:10px;max-width:400px;margin:0 auto;'>" . __h('setup_email_error') . "</div></div>";
        echo "<meta http-equiv='refresh' content='3; url=login.php?mode=adduser'>";
        exit;
    }
    
    if (!in_array($group, ['admin', 'group1', 'group2', 'group3', 'group4'])) $group = 'group2';
    if (!is_dir("./src")) mkdir("./src", 0755, true);
    
    // ✅ 삭제/탈퇴 사용자 아이디 재사용 방지
    if (is_deleted_user_id($id)) {
        echo "<div style='padding:50px;text-align:center;'><div style='background:#f8d7da;color:#721c24;padding:20px;border-radius:10px;max-width:400px;margin:0 auto;'>" . __h('signup_error_id_deleted') . "</div></div>";
        echo "<meta http-equiv='refresh' content='3; url=login.php?mode=adduser'>";
        exit;
    }
    
    // ✅ users.json 사용 (순수 JSON)
    $user_arr = load_users();
    $user_arr[$id] = [
        'pass' => password_hash(hash("sha256", $pass), PASSWORD_DEFAULT), 
        'group' => $group,
        'email' => $email,
        'created_at' => $user_arr[$id]['created_at'] ?? date('Y-m-d H:i:s')
    ];
    save_users($user_arr);
    
    echo "<div style='padding:50px;text-align:center;'><div style='background:#d4edda;color:#155724;padding:20px;border-radius:10px;max-width:400px;margin:0 auto;'><h3>" . __h('setup_complete') . "</h3><p>".h($id)." / ".h($group)."</p></div></div>";
    echo "<meta http-equiv='refresh' content='3; url=admin.php'>";
    exit;

// ============================================================
// ✅ 회원가입 처리
// ============================================================
} elseif (isset($_POST['mode']) && $_POST['mode'] === "signup") {
    // 회원가입 설정 확인
    $reg_settings = get_app_settings('registration', ['enabled' => false, 'require_approval' => true]);
    if (empty($reg_settings['enabled'])) {
        $_SESSION['signup_error'] = __('signup_error_disabled');
        header("Location: login.php");
        exit;
    }
    
    $id = trim($_POST['id'] ?? '');
    $pass = $_POST['pass'] ?? '';
    $pass_confirm = $_POST['pass_confirm'] ?? '';
    $email = trim($_POST['email'] ?? '');
    
    // ✅ 약관 동의 확인
    $terms_settings = get_app_settings('terms', ['enabled' => false, 'content' => '']);
    if ($terms_settings['enabled'] && !empty($terms_settings['content'])) {
        if (empty($_POST['agree_terms'])) {
            $_SESSION['signup_error'] = __('signup_error_terms');
            header("Location: login.php?mode=signup");
            exit;
        }
    }
    
    // 유효성 검사
    if (!validateUserId($id)) {
        $_SESSION['signup_error'] = __('signup_error_id_format');
        header("Location: login.php?mode=signup");
        exit;
    }
    
    if (!validatePassword($pass)) {
        $_SESSION['signup_error'] = __('signup_error_password_min');
        header("Location: login.php?mode=signup");
        exit;
    }
    
    if ($pass !== $pass_confirm) {
        $_SESSION['signup_error'] = __('signup_error_password_mismatch');
        header("Location: login.php?mode=signup");
        exit;
    }
    
    // 이메일은 선택사항 - 입력된 경우에만 유효성 검사
    if (!empty($email) && !filter_var($email, FILTER_VALIDATE_EMAIL)) {
        $_SESSION['signup_error'] = __('signup_error_invalid_email');
        header("Location: login.php?mode=signup");
        exit;
    }
    
    // 중복 확인
    $user_arr = load_users();
    if (isset($user_arr[$id])) {
        $_SESSION['signup_error'] = __('signup_error_id_exists');
        header("Location: login.php?mode=signup");
        exit;
    }
    
    // 삭제/탈퇴 사용자 아이디 재사용 방지
    if (is_deleted_user_id($id)) {
        $_SESSION['signup_error'] = __('signup_error_id_deleted');
        header("Location: login.php?mode=signup");
        exit;
    }
    
    // 이메일 중복 확인 (이메일이 입력된 경우에만)
    if (!empty($email)) {
        foreach ($user_arr as $uid => $udata) {
            if (isset($udata['email']) && !empty($udata['email']) && strtolower($udata['email']) === strtolower($email)) {
                $_SESSION['signup_error'] = __('signup_error_email_exists');
                header("Location: login.php?mode=signup");
                exit;
            }
        }
    }
    
    // 사용자 생성
    $require_approval = $reg_settings['require_approval'] ?? true;
    $user_arr[$id] = [
        'pass' => password_hash(hash("sha256", $pass), PASSWORD_DEFAULT),
        'group' => 'group2',
        'email' => $email,
        'status' => $require_approval ? 'pending' : 'active',
        'created_at' => date('Y-m-d H:i:s')
    ];
    save_users($user_arr);
    
    // 로그인 로그 기록
    if (function_exists('log_login_attempt')) {
        log_login_attempt($id, true, '회원가입');
    }
    
    if ($require_approval) {
        $_SESSION['signup_success'] = __('signup_success_approval');
    } else {
        $_SESSION['signup_success'] = __('signup_success');
    }
    header("Location: login.php?mode=signup");
    exit;

} elseif (isset($_POST['mode']) && $_POST['mode'] === "login") {
    // ✅ users.json 사용 (순수 JSON)
    if (!users_file_exists()) { $_SESSION['login_error'] = __('login_error_no_user_file'); header("Location: login.php"); exit; }
    
    $user_arr = load_users();
    $id = trim($_POST['id'] ?? '');
    $pass = $_POST['pass'] ?? '';
    
    if (empty($id) || empty($pass)) { $_SESSION['login_error'] = __('login_error_empty'); header("Location: login.php"); exit; }
    if (!isset($user_arr[$id])) { 
        $ipBlocker->recordLoginFailure(null, $id); // 브루트포스 기록
        $_SESSION['login_error'] = __('login_error_not_found'); 
        header("Location: login.php"); 
        exit; 
    }
    
    $hashed = hash("sha256", $pass);
    if (password_verify($hashed, $user_arr[$id]['pass'])) {
        
        // ✅ 사용자 상태 체크 (정지/대기)
        $user_status = $user_arr[$id]['status'] ?? 'active';
        if ($user_status === 'pending') {
            $_SESSION['login_error'] = __('login_error_pending');
            header("Location: login.php");
            exit;
        }
        if ($user_status === 'suspended') {
            $suspend_end = $user_arr[$id]['suspend_end'] ?? null;
            if ($suspend_end) {
                $end_date = strtotime($suspend_end);
                if ($end_date && $end_date > time()) {
                    $_SESSION['login_error'] = __('login_error_suspended', date('Y-m-d', $end_date));
                    header("Location: login.php");
                    exit;
                } else {
                    // 정지 기간 만료 - 자동 해제
                    $user_arr[$id]['status'] = 'active';
                    $user_arr[$id]['suspend_reason'] = null;
                    $user_arr[$id]['suspend_start'] = null;
                    $user_arr[$id]['suspend_end'] = null;
                    save_users($user_arr);
                }
            }
        }
        
        // ✅ 2FA 체크 - 해당 사용자가 2FA 활성화했는지 확인
        if (is_user_2fa_enabled($id)) {
            // 2FA 필요 - 임시 세션에 저장하고 OTP 입력 화면으로
            $_SESSION['2fa_pending'] = true;
            $_SESSION['2fa_user_id'] = $id;
            $_SESSION['2fa_user_pass'] = $hashed;
            $_SESSION['2fa_remember_me'] = isset($_POST['remember_me']) && $_POST['remember_me'] === '1';
            $_SESSION['2fa_timestamp'] = time();
            header("Location: login.php?mode=2fa");
            exit;
        }
        
        clearUserCache($id);
        $ipBlocker->clearLoginAttempts(); // 브루트포스 기록 초기화
        
        // ✅ 로그인 로그 JSON 형식으로 저장 (파일 잠금)
        $log_file = __DIR__ . "/src/login_log.json";
        $fp = fopen($log_file, 'c+');
        if ($fp) {
            if (flock($fp, LOCK_EX)) {
                $content = stream_get_contents($fp);
                $log_arr = json_decode($content, true) ?? [];
                
                // ✅ 최대 5000개 유지 (활동 로그와 동일)
                if (count($log_arr) >= 5000) {
                    $log_arr = array_slice($log_arr, -4000);
                }
                
                // 국가 정보 가져오기
                $login_ip = filter_var($_SERVER['REMOTE_ADDR'], FILTER_VALIDATE_IP) ?: 'unknown';
                $login_country = 'UNKNOWN';
                if (file_exists(__DIR__ . '/ip_block.php')) {
                    require_once __DIR__ . '/ip_block.php';
                    $ipBlockerForLog = new IPBlocker(__DIR__ . '/src/ip_block_settings.json');
                    $login_country = $ipBlockerForLog->getCountryByIP($login_ip);
                }
                
                // ✅ 한국 시간 사용 (활동 로그와 동일)
                $kst = new DateTime('now', new DateTimeZone('Asia/Seoul'));
                
                // 새 로그 항목 추가
                $log_arr[] = [
                    'datetime' => $kst->format('Y-m-d H:i:s'),
                    'user_id' => preg_replace('/[^a-zA-Z0-9_]/', '', $id),
                    'ip' => $login_ip,
                    'country' => $login_country,
                    'user_agent' => substr(preg_replace('/[\r\n]/', '', $_SERVER['HTTP_USER_AGENT'] ?? ''), 0, 200)
                ];
                
                ftruncate($fp, 0);
                rewind($fp);
                fwrite($fp, json_encode($log_arr, JSON_UNESCAPED_UNICODE | JSON_PRETTY_PRINT));
                fflush($fp);
                flock($fp, LOCK_UN);
            }
            fclose($fp);
        }
        
        // ✅ 세션 고정 공격 방지 (Session Fixation Prevention)
        // 로그인 성공 시 세션 ID를 재생성하여 공격자가 미리 설정한 세션 ID 무효화
        session_unset(); 
        session_destroy(); 
        session_start();
        session_regenerate_id(true);  // 새 세션 ID 생성 및 이전 세션 파일 삭제
        
        $_SESSION['user_id'] = $id;
        $_SESSION['user_pass'] = $hashed;
        $_SESSION['user_group'] = $user_arr[$id]['group'];
        $_SESSION['last_action'] = time();
        
        // ✅ 캐시 갱신 플래그 초기화 (새 콘텐츠 반영을 위해)
        unset($_SESSION['index_refreshed']);
        unset($_SESSION['zip_cache_generated']);
        unset($_SESSION['filelist_cache_generated']);
        
        // ✅ 로그인 유지 체크 시 쿠키 설정 (무제한) + 세션 플래그
        if (isset($_POST['remember_me']) && $_POST['remember_me'] === '1') {
            $token = create_remember_token($id, 3650); // 10년
            $cookie_options = [
                'expires' => time() + (3650 * 24 * 60 * 60), // 10년
                'path' => '/',
                'secure' => isset($_SERVER['HTTPS']) && $_SERVER['HTTPS'] === 'on',
                'httponly' => true,
                'samesite' => 'Lax'
            ];
            setcookie('remember_token', $token, $cookie_options);
            $_SESSION['remember_me'] = true; // 비활동 자동 로그아웃 무시 플래그
        }
        
        header("Location: index.php" . $bidx_query); exit;
    } else {
        $ipBlocker->recordLoginFailure(null, $id); // 브루트포스 기록
        $_SESSION['login_error'] = __('login_error_wrong_password');
        header("Location: login.php"); exit;
    }

// ============================================================
// ✅ 아이디 찾기 처리
// ============================================================
} elseif (isset($_POST['mode']) && $_POST['mode'] === "find_id") {
    $email = trim($_POST['email'] ?? '');
    
    if (empty($email) || !filter_var($email, FILTER_VALIDATE_EMAIL)) {
        $_SESSION['find_error'] = __('signup_error_invalid_email');
        header("Location: login.php?mode=find_id");
        exit;
    }
    
    $ua = load_users();
    $found_ids = [];
    
    foreach ($ua as $uid => $udata) {
        if (isset($udata['email']) && strtolower($udata['email']) === strtolower($email)) {
            // 아이디 마스킹 (첫 2자 + *** + 마지막 1자)
            $len = strlen($uid);
            if ($len <= 3) {
                $masked = substr($uid, 0, 1) . str_repeat('*', $len - 1);
            } else {
                $masked = substr($uid, 0, 2) . str_repeat('*', $len - 3) . substr($uid, -1);
            }
            $found_ids[] = $masked;
        }
    }
    
    if (!empty($found_ids)) {
        $_SESSION['find_success'] = __('find_id_success', implode(', ', $found_ids));
    } else {
        $_SESSION['find_error'] = __('find_id_error_no_result');
    }
    header("Location: login.php?mode=find_id");
    exit;

// ============================================================
// ✅ 비밀번호 찾기 처리
// ============================================================
} elseif (isset($_POST['mode']) && $_POST['mode'] === "find_password") {
    $id = trim($_POST['id'] ?? '');
    $email = trim($_POST['email'] ?? '');
    
    if (empty($id) || empty($email)) {
        $_SESSION['find_error'] = __('find_password_error_empty');
        header("Location: login.php?mode=find_password");
        exit;
    }
    
    if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
        $_SESSION['find_error'] = __('signup_error_invalid_email');
        header("Location: login.php?mode=find_password");
        exit;
    }
    
    $ua = load_users();
    
    if (!isset($ua[$id])) {
        $_SESSION['find_error'] = __('login_error_not_found');
        header("Location: login.php?mode=find_password");
        exit;
    }
    
    $user_email = $ua[$id]['email'] ?? '';
    if (empty($user_email) || strtolower($user_email) !== strtolower($email)) {
        $_SESSION['find_error'] = __('find_password_error_mismatch');
        header("Location: login.php?mode=find_password");
        exit;
    }
    
    // 임시 비밀번호 생성 (8자리)
    $temp_password = substr(str_shuffle('abcdefghjkmnpqrstuvwxyzABCDEFGHJKMNPQRSTUVWXYZ23456789'), 0, 8);
    
    // 비밀번호 저장
    $ua[$id]['pass'] = password_hash(hash("sha256", $temp_password), PASSWORD_DEFAULT);
    $ua[$id]['password_reset_at'] = date('Y-m-d H:i:s');
    save_users($ua);
    
    // ✅ SMTP 설정이 있으면 이메일 발송, 없으면 화면에 표시
    $email_sent = false;
    $email_result = send_password_reset_email($email, $id, $temp_password);
    
    if ($email_result === true) {
        $email_sent = true;
        $_SESSION['find_success'] = __('find_password_email_sent', $email);
    } else {
        // 이메일 발송 실패 또는 SMTP 미설정 - 화면에 표시
        $_SESSION['temp_password'] = $temp_password;
        $_SESSION['temp_password_user'] = $id;
        $_SESSION['find_success'] = __('find_password_reset_success');
    }
    
    header("Location: login.php?mode=find_password");
    exit;

} elseif (isset($_GET['mode']) && $_GET['mode'] === "logout") {
    if (!empty($_SESSION['user_id'])) clearUserCache($_SESSION['user_id']);
    
    // ✅ 수동 로그아웃 시에만 토큰 삭제
    if (isset($_COOKIE['remember_token'])) {
        delete_remember_token($_COOKIE['remember_token']);
        setcookie('remember_token', '', time() - 3600, '/');
    }
    
    session_unset(); session_destroy();
    header("Location: login.php"); exit;

} elseif (isset($_GET['mode']) && $_GET['mode'] === "logout_all") {
    // ✅ 모든 기기에서 로그아웃
    $user_id = $_SESSION['user_id'] ?? null;
    
    if (!empty($user_id)) {
        clearUserCache($user_id);
        delete_user_remember_tokens($user_id); // 해당 사용자의 모든 토큰 삭제
    }
    
    // 현재 기기 쿠키도 삭제
    if (isset($_COOKIE['remember_token'])) {
        setcookie('remember_token', '', time() - 3600, '/');
    }
    
    session_unset(); session_destroy(); session_start();
    $_SESSION['login_error'] = __('login_all_devices_logout');
    header("Location: login.php"); exit;

} elseif (isset($_GET['mode']) && $_GET['mode'] === "timeout") {
    $msg = $_SESSION['timeout_message'] ?? __('login_timeout_message');
    if (!empty($_SESSION['user_id'])) clearUserCache($_SESSION['user_id']);
    
    // ✅ 자동 로그아웃 시에는 토큰 유지 (로그인 유지 사용자는 자동 재로그인됨)
    // 토큰이 있으면 init.php에서 자동 로그인 처리
    
    session_unset(); session_destroy(); session_start();
    $_SESSION['login_error'] = $msg;
    header("Location: login.php"); exit;

// ============================================================
// ✅ 2FA OTP 검증 처리
// ============================================================
} elseif (isset($_POST['mode']) && $_POST['mode'] === "2fa_verify") {
    // 2FA 세션 유효성 검사
    if (empty($_SESSION['2fa_pending']) || empty($_SESSION['2fa_user_id'])) {
        $_SESSION['login_error'] = __('2fa_error_expired');
        header("Location: login.php");
        exit;
    }
    
    // 타임아웃 체크 (5분)
    if (time() - ($_SESSION['2fa_timestamp'] ?? 0) > 300) {
        unset($_SESSION['2fa_pending'], $_SESSION['2fa_user_id'], $_SESSION['2fa_user_pass'], $_SESSION['2fa_remember_me'], $_SESSION['2fa_timestamp']);
        $_SESSION['login_error'] = __('2fa_error_timeout');
        header("Location: login.php");
        exit;
    }
    
    $otp_code = $_POST['otp_code'] ?? '';
    $user_id_2fa = $_SESSION['2fa_user_id'];
    
    // OTP 또는 백업 코드 검증 (사용자별)
    $valid = verify_user_totp($user_id_2fa, $otp_code) || verify_user_backup_code($user_id_2fa, $otp_code);
    
    if (!$valid) {
        $ipBlocker->recordLoginFailure(null, $user_id_2fa);
        $_SESSION['2fa_error'] = __('2fa_error_invalid');
        header("Location: login.php?mode=2fa");
        exit;
    }
    
    // 2FA 검증 성공 - 실제 로그인 처리
    $id = $_SESSION['2fa_user_id'];
    $hashed = $_SESSION['2fa_user_pass'];
    $remember_me = $_SESSION['2fa_remember_me'] ?? false;
    
    // 2FA 세션 정리
    unset($_SESSION['2fa_pending'], $_SESSION['2fa_user_id'], $_SESSION['2fa_user_pass'], $_SESSION['2fa_remember_me'], $_SESSION['2fa_timestamp'], $_SESSION['2fa_error']);
    
    $user_arr = load_users();
    
    clearUserCache($id);
    $ipBlocker->clearLoginAttempts();
    
    // 로그인 로그 저장
    $log_file = __DIR__ . "/src/login_log.json";
    $fp = fopen($log_file, 'c+');
    if ($fp) {
        if (flock($fp, LOCK_EX)) {
            $content = stream_get_contents($fp);
            $log_arr = json_decode($content, true) ?? [];
            
            // ✅ 최대 5000개 유지 (활동 로그와 동일)
            if (count($log_arr) >= 5000) {
                $log_arr = array_slice($log_arr, -4000);
            }
            
            // 국가 정보 가져오기
            $login_ip = filter_var($_SERVER['REMOTE_ADDR'], FILTER_VALIDATE_IP) ?: 'unknown';
            $login_country = $ipBlocker->getCountryByIP($login_ip);
            
            // ✅ 한국 시간 사용 (활동 로그와 동일)
            $kst = new DateTime('now', new DateTimeZone('Asia/Seoul'));
            
            $log_arr[] = [
                'datetime' => $kst->format('Y-m-d H:i:s'),
                'user_id' => preg_replace('/[^a-zA-Z0-9_]/', '', $id),
                'ip' => $login_ip,
                'country' => $login_country,
                'user_agent' => substr(preg_replace('/[\r\n]/', '', $_SERVER['HTTP_USER_AGENT'] ?? ''), 0, 200),
                '2fa' => true
            ];
            ftruncate($fp, 0);
            rewind($fp);
            fwrite($fp, json_encode($log_arr, JSON_UNESCAPED_UNICODE | JSON_PRETTY_PRINT));
            fflush($fp);
            flock($fp, LOCK_UN);
        }
        fclose($fp);
    }
    
    // 세션 고정 공격 방지
    session_unset();
    session_destroy();
    session_start();
    session_regenerate_id(true);
    
    $_SESSION['user_id'] = $id;
    $_SESSION['user_pass'] = $hashed;
    $_SESSION['user_group'] = $user_arr[$id]['group'];
    $_SESSION['last_action'] = time();
    
    unset($_SESSION['index_refreshed']);
    unset($_SESSION['zip_cache_generated']);
    unset($_SESSION['filelist_cache_generated']);
    
    // 로그인 유지 처리
    if ($remember_me) {
        $token = create_remember_token($id, 3650);
        $cookie_options = [
            'expires' => time() + (3650 * 24 * 60 * 60),
            'path' => '/',
            'secure' => isset($_SERVER['HTTPS']) && $_SERVER['HTTPS'] === 'on',
            'httponly' => true,
            'samesite' => 'Lax'
        ];
        setcookie('remember_token', $token, $cookie_options);
        $_SESSION['remember_me'] = true;
    }
    
    header("Location: index.php" . $bidx_query);
    exit;

// 2FA 취소 (돌아가기)
} elseif (isset($_GET['mode']) && $_GET['mode'] === "2fa_cancel") {
    unset($_SESSION['2fa_pending'], $_SESSION['2fa_user_id'], $_SESSION['2fa_user_pass'], $_SESSION['2fa_remember_me'], $_SESSION['2fa_timestamp'], $_SESSION['2fa_error']);
    header("Location: login.php");
    exit;
}

$theme_data = load_login_theme();
$theme = $theme_data['theme'];
$theme_backgrounds = $theme_data['backgrounds'];
$theme_filters = $theme_data['filters'] ?? [];

// 현재 테마의 커스텀 배경 가져오기 (JSON 키는 문자열이므로 문자열로 접근)
$custom_bg = $theme_backgrounds[(string)$theme] ?? '';

// 현재 테마의 배경 필터 가져오기
$current_filter = $theme_filters[(string)$theme] ?? 'none';

// 필터 CSS 값 생성
$filter_css_map = [
    'none' => 'none',
    'blur' => 'blur(5px)',
    'grayscale' => 'grayscale(100%)',
    'sepia' => 'sepia(80%)',
    'brightness' => 'brightness(1.2)',
    'contrast' => 'contrast(1.3)',
    'saturate' => 'saturate(1.5)',
    'invert' => 'invert(100%)',
    'hue-rotate' => 'hue-rotate(90deg)',
    'blur-grayscale' => 'blur(3px) grayscale(100%)',
    'blur-sepia' => 'blur(3px) sepia(80%)',
    'brightness-contrast' => 'brightness(1.1) contrast(1.2)',
    'vintage' => 'sepia(50%) contrast(1.1) brightness(0.9) saturate(0.8)',
    'cool' => 'hue-rotate(180deg) saturate(0.8) brightness(1.1)',
    'warm' => 'sepia(30%) saturate(1.3) brightness(1.05)'
];
$bg_filter_css = $filter_css_map[$current_filter] ?? 'none';

// 캐시 버스팅용 타임스탬프 (배경 변경 시 캐시 무효화)
$bg_cache_ver = '';
if (!empty($custom_bg)) {
    $theme_file = './src/login_theme.json';
    $bg_cache_ver = file_exists($theme_file) ? filemtime($theme_file) : time();
    // URL에 캐시 버스팅 파라미터 추가
    $separator = (strpos($custom_bg, '?') !== false) ? '&' : '?';
    $custom_bg .= $separator . 'v=' . $bg_cache_ver;
}

// 테마 0번 기본 배경 (상수에서 로드)
$theme_0_default_bg = '';
if ($theme == 0 && empty($custom_bg) && defined('THEME_0_DEFAULT_BG') && THEME_0_DEFAULT_BG !== '') {
    $theme_0_default_bg = 'data:image/jpeg;base64,' . THEME_0_DEFAULT_BG;
}

$branding = load_branding();
$page = 'login';

// ✅ 회원 설정 로드
$reg_settings = get_app_settings('registration', ['enabled' => false, 'require_approval' => true, 'find_id_enabled' => true, 'find_password_enabled' => true]);
$registration_enabled = $reg_settings['enabled'] ?? false;
$find_id_enabled = $reg_settings['find_id_enabled'] ?? true;
$find_password_enabled = $reg_settings['find_password_enabled'] ?? true;

// ✅ users.json 또는 레거시 user.php 존재 여부 확인
if (!users_file_exists()) $page = 'setup';
elseif (isset($_GET['mode']) && $_GET['mode'] === '2fa' && !empty($_SESSION['2fa_pending'])) $page = '2fa';
elseif (isset($_GET['mode']) && $_GET['mode'] === 'find_id' && $find_id_enabled) $page = 'find_id';
elseif (isset($_GET['mode']) && $_GET['mode'] === 'find_password' && $find_password_enabled) $page = 'find_password';
elseif (isset($_GET['mode']) && $_GET['mode'] === 'signup' && $registration_enabled) $page = 'signup';
elseif (isset($_SESSION['user_id']) && isset($_GET['mode']) && $_GET['mode'] === 'adduser' && ($_SESSION['user_group'] ?? '') === 'admin') $page = 'adduser';
elseif (isset($_SESSION['user_id'])) { header("Location: index.php" . $bidx_query); exit; }
?>
