    <script>
    function toggleBackupCode() {
        var otpSec = document.getElementById('otp-section');
        var backupSec = document.getElementById('backup-section');
        var otpInput = document.getElementById('otp-input');
        var backupInput = document.getElementById('backup-input');
        
        if (otpSec.style.display !== 'none') {
            otpSec.style.display = 'none';
            backupSec.style.display = 'block';
            otpInput.removeAttribute('required');
            otpInput.name = '';
            otpInput.value = '';
            backupInput.setAttribute('required', 'required');
            backupInput.name = 'otp_code';
            backupInput.focus();
        } else {
            otpSec.style.display = 'block';
            backupSec.style.display = 'none';
            backupInput.removeAttribute('required');
            backupInput.name = '';
            backupInput.value = '';
            otpInput.setAttribute('required', 'required');
            otpInput.name = 'otp_code';
            otpInput.focus();
        }
    }
    </script>
    
