<script>
(function(){
    var remaining = <?php echo $remaining; ?>;
    var timerEl = document.getElementById('2fa-timer');
    var interval = setInterval(function(){
        remaining--;
        if(remaining <= 0){
            clearInterval(interval);
            location.href = 'login.php?mode=2fa_cancel';
            return;
        }
        var m = Math.floor(remaining/60);
        var s = remaining % 60;
        timerEl.textContent = m + ':' + (s<10?'0':'') + s;
    }, 1000);
})();
</script>

