<script>
const bookColors=['#c9302c','#337ab7','#5cb85c','#f0ad4e','#5bc0de','#9b59b6','#e74c3c','#3498db','#2ecc71','#f39c12','#1abc9c','#34495e','#e67e22','#16a085','#27ae60','#2980b9','#8e44ad','#c0392b','#d35400','#7f8c8d','#6c3483','#1e8449','#a93226','#1f618d','#b9770e','#784212','#5d6d7e','#283747','#7d3c98','#196f3d'];
function createBooks(shelfId,count){const shelf=document.getElementById(shelfId);if(!shelf)return;shelf.innerHTML='';for(let i=0;i<count;i++){const book=document.createElement('div');book.className='book';const height=60+Math.random()*40;const width=15+Math.random()*20;const color=bookColors[Math.floor(Math.random()*bookColors.length)];book.style.setProperty('--h',height+'px');book.style.setProperty('--w',width+'px');book.style.setProperty('--color',color);if(Math.random()>0.85){book.classList.add('tilted');book.style.setProperty('--tilt',(-5-Math.random()*10)+'deg');}shelf.appendChild(book);}}
function initShelves(){const width=window.innerWidth;const booksPerShelf=Math.floor(width/30);for(let i=1;i<=5;i++){createBooks('shelf'+i,booksPerShelf);}}
initShelves();window.addEventListener('resize',initShelves);
