<script>
(function() {
    const bookColors = [
        '#c9302c', '#337ab7', '#5cb85c', '#f0ad4e', '#5bc0de',
        '#9b59b6', '#e74c3c', '#3498db', '#2ecc71', '#f39c12',
        '#1abc9c', '#34495e', '#e67e22', '#16a085', '#27ae60',
        '#2980b9', '#8e44ad', '#c0392b', '#d35400', '#7f8c8d'
    ];
    function createBooks(shelfId, count) {
        const shelf = document.getElementById(shelfId);
        if (!shelf) return;
        shelf.innerHTML = '';
        for (let i = 0; i < count; i++) {
            const book = document.createElement('div');
            book.className = 'theme-0-book';
            book.style.setProperty('--h', (50 + Math.random() * 35) + 'px');
            book.style.setProperty('--w', (12 + Math.random() * 16) + 'px');
            book.style.setProperty('--color', bookColors[Math.floor(Math.random() * bookColors.length)]);
            if (Math.random() > 0.85) {
                book.classList.add('tilted');
                book.style.setProperty('--tilt', (-5 - Math.random() * 10) + 'deg');
            }
            shelf.appendChild(book);
        }
    }
    function initShelves() {
        const booksPerShelf = Math.floor(window.innerWidth / 28);
        for (let i = 1; i <= 5; i++) createBooks('shelf' + i, booksPerShelf);
    }
    initShelves();
    window.addEventListener('resize', initShelves);
})();
</script>
