<?php elseif($theme == 12): /* 오로라 - 물결 효과 */ ?>
<div id="auroraContainer"></div>
<script>
(function() {
    const container = document.getElementById('auroraContainer');
    if (!container) return;
    
    const canvas = document.createElement('canvas');
    canvas.style.cssText = 'width:100%;height:100%;';
    container.appendChild(canvas);
    
    const ctx = canvas.getContext('2d');
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    
    let time = 0;
    
    // 별 생성
    const stars = [];
    for (let i = 0; i < 150; i++) {
        stars.push({
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height * 0.7,
            size: Math.random() * 2 + 0.5,
            twinkle: Math.random() * Math.PI * 2
        });
    }
    
    function drawAurora() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        
        // 별 그리기
        stars.forEach(star => {
            star.twinkle += 0.02;
            ctx.beginPath();
            ctx.arc(star.x, star.y, star.size * (0.6 + Math.sin(star.twinkle) * 0.4), 0, Math.PI * 2);
            ctx.fillStyle = `rgba(255,255,255,${0.4 + Math.sin(star.twinkle) * 0.4})`;
            ctx.fill();
        });
        
        // 오로라 커튼 레이어
        const layers = [
            { color1: '0,255,127', color2: '0,255,200', offset: 0, height: 0.55 },
            { color1: '0,200,255', color2: '100,255,200', offset: 1, height: 0.45 },
            { color1: '150,100,255', color2: '0,255,150', offset: 2, height: 0.5 },
            { color1: '255,100,255', color2: '0,255,255', offset: 3, height: 0.4 }
        ];
        
        layers.forEach(layer => {
            ctx.beginPath();
            
            for (let x = 0; x <= canvas.width; x += 5) {
                const wave1 = Math.sin(x * 0.003 + time * 0.8 + layer.offset) * 60;
                const wave2 = Math.sin(x * 0.007 + time * 1.2 + layer.offset * 0.5) * 40;
                const wave3 = Math.sin(x * 0.001 + time * 0.5 + layer.offset * 2) * 80;
                const y = canvas.height * layer.height + wave1 + wave2 + wave3;
                
                if (x === 0) ctx.moveTo(x, y);
                else ctx.lineTo(x, y);
            }
            
            ctx.lineTo(canvas.width, canvas.height);
            ctx.lineTo(0, canvas.height);
            ctx.closePath();
            
            const gradient = ctx.createLinearGradient(0, canvas.height * 0.15, 0, canvas.height);
            gradient.addColorStop(0, `rgba(${layer.color1},0.35)`);
            gradient.addColorStop(0.3, `rgba(${layer.color2},0.2)`);
            gradient.addColorStop(0.6, `rgba(${layer.color1},0.08)`);
            gradient.addColorStop(1, 'transparent');
            ctx.fillStyle = gradient;
            ctx.fill();
        });
        
        // 수직 광선 효과
        for (let i = 0; i < 25; i++) {
            const x = (i / 25) * canvas.width + Math.sin(time + i) * 30;
            const height = canvas.height * (0.4 + Math.sin(time * 0.7 + i * 0.5) * 0.25);
            const alpha = 0.08 + Math.sin(time + i * 0.3) * 0.05;
            
            const rayGradient = ctx.createLinearGradient(x, canvas.height * 0.05, x, canvas.height * 0.05 + height);
            rayGradient.addColorStop(0, `rgba(0,255,180,${alpha})`);
            rayGradient.addColorStop(0.5, `rgba(100,255,200,${alpha * 0.6})`);
            rayGradient.addColorStop(1, 'transparent');
            
            ctx.fillStyle = rayGradient;
            ctx.fillRect(x - 15, canvas.height * 0.05, 30, height);
        }
        
        time += 0.012;
        requestAnimationFrame(drawAurora);
    }
    drawAurora();
    
    window.addEventListener('resize', () => {
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;
        stars.length = 0;
        for (let i = 0; i < 150; i++) {
            stars.push({
                x: Math.random() * canvas.width,
                y: Math.random() * canvas.height * 0.7,
                size: Math.random() * 2 + 0.5,
                twinkle: Math.random() * Math.PI * 2
            });
        }
    });
})();
</script>

