<div id="starwarsContainer"></div>
<script>
(function() {
    const container = document.getElementById('starwarsContainer');
    if (!container) return;
    
    const canvas = document.createElement('canvas');
    canvas.style.cssText = 'width:100%;height:100%;';
    container.appendChild(canvas);
    
    const ctx = canvas.getContext('2d');
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    
    const stars = [];
    const centerX = canvas.width / 2;
    const centerY = canvas.height / 2;
    
    for (let i = 0; i < 200; i++) {
        stars.push({
            x: Math.random() * canvas.width - centerX,
            y: Math.random() * canvas.height - centerY,
            z: Math.random() * canvas.width
        });
    }
    
    function drawStars() {
        ctx.fillStyle = 'rgba(0,0,0,0.2)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        
        for (let star of stars) {
            star.z -= 5;
            if (star.z <= 0) {
                star.x = Math.random() * canvas.width - centerX;
                star.y = Math.random() * canvas.height - centerY;
                star.z = canvas.width;
            }
            
            const sx = (star.x / star.z) * 300 + centerX;
            const sy = (star.y / star.z) * 300 + centerY;
            const size = (1 - star.z / canvas.width) * 3;
            
            ctx.beginPath();
            ctx.fillStyle = `rgba(255,232,31,${1 - star.z / canvas.width})`;
            ctx.arc(sx, sy, size, 0, Math.PI * 2);
            ctx.fill();
        }
        requestAnimationFrame(drawStars);
    }
    drawStars();
    
    window.addEventListener('resize', () => {
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;
    });
})();
</script>

<?php elseif($theme == 21): /* 별자리 연결 */ ?>
<div id="constellationContainer"></div>
<script>
(function() {
    const container = document.getElementById('constellationContainer');
    if (!container) return;
    
    const canvas = document.createElement('canvas');
    canvas.style.cssText = 'width:100%;height:100%;';
    container.appendChild(canvas);
    
    const ctx = canvas.getContext('2d');
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    
    const stars = [];
    for (let i = 0; i < 120; i++) {
        stars.push({
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height,
            size: Math.random() * 2 + 1,
            speed: Math.random() * 0.3 + 0.1,
            twinkle: Math.random() * Math.PI * 2
        });
    }
    
    function draw() {
        ctx.fillStyle = 'rgba(10,10,46,0.1)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        
        stars.forEach((star, i) => {
            star.twinkle += 0.02;
            const brightness = 0.5 + Math.sin(star.twinkle) * 0.5;
            
            ctx.beginPath();
            ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
            ctx.fillStyle = `rgba(100,149,237,${brightness})`;
            ctx.fill();
            
            // 별자리 연결선
            stars.forEach((star2, j) => {
                if (i < j) {
                    const dist = Math.hypot(star.x - star2.x, star.y - star2.y);
                    if (dist < 120) {
                        ctx.beginPath();
                        ctx.moveTo(star.x, star.y);
                        ctx.lineTo(star2.x, star2.y);
                        ctx.strokeStyle = `rgba(100,149,237,${0.3 - dist/400})`;
                        ctx.lineWidth = 0.5;
                        ctx.stroke();
                    }
                }
            });
            
            star.y += star.speed;
            if (star.y > canvas.height + 10) {
                star.y = -10;
                star.x = Math.random() * canvas.width;
            }
        });
        requestAnimationFrame(draw);
    }
    draw();
    
    window.addEventListener('resize', () => {
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;
    });
})();
</script>

