<div id="milkywayContainer"></div>
<script>
(function() {
    const container = document.getElementById('milkywayContainer');
    if (!container) return;
    
    const canvas = document.createElement('canvas');
    canvas.style.cssText = 'width:100%;height:100%;';
    container.appendChild(canvas);
    
    const ctx = canvas.getContext('2d');
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    
    const particles = [];
    for (let i = 0; i < 400; i++) {
        const t = Math.random();
        const baseX = t * canvas.width * 1.5 - canvas.width * 0.25;
        const baseY = t * canvas.height;
        const spread = (Math.random() - 0.5) * 200;
        
        particles.push({
            baseX: baseX,
            baseY: baseY,
            spread: spread,
            x: baseX + spread * 0.7,
            y: baseY + spread * 0.3,
            size: Math.random() * 2.5 + 0.5,
            offset: Math.random() * Math.PI * 2,
            color: `hsl(${Math.random() * 60 + 260}, 70%, ${Math.random() * 30 + 50}%)`
        });
    }
    
    let time = 0;
    function draw() {
        ctx.fillStyle = 'rgba(26,10,62,0.05)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        
        particles.forEach(p => {
            p.x = p.baseX + Math.sin(time + p.offset) * 30 + p.spread * 0.7;
            p.y = p.baseY + Math.cos(time + p.offset) * 15 + p.spread * 0.3;
            
            ctx.beginPath();
            ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
            ctx.fillStyle = p.color;
            ctx.fill();
        });
        
        time += 0.008;
        requestAnimationFrame(draw);
    }
    draw();
    
    window.addEventListener('resize', () => {
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;
    });
})();
</script>

