<div id="nebulaContainer"></div>
<script>
(function() {
    const container = document.getElementById('nebulaContainer');
    if (!container) return;
    
    const canvas = document.createElement('canvas');
    canvas.style.cssText = 'width:100%;height:100%;';
    container.appendChild(canvas);
    
    const ctx = canvas.getContext('2d');
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    
    const clouds = [];
    for (let i = 0; i < 25; i++) {
        clouds.push({
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height,
            size: Math.random() * 150 + 80,
            color: `hsla(${Math.random() * 60 + 180}, 80%, 50%, 0.08)`,
            speedX: (Math.random() - 0.5) * 0.3,
            speedY: (Math.random() - 0.5) * 0.2
        });
    }
    
    const stars = [];
    for (let i = 0; i < 100; i++) {
        stars.push({
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height,
            size: Math.random() * 2,
            twinkle: Math.random() * Math.PI * 2
        });
    }
    
    let time = 0;
    function draw() {
        ctx.fillStyle = 'rgba(30,10,50,0.03)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        
        // 성운 구름
        clouds.forEach(cloud => {
            const gradient = ctx.createRadialGradient(cloud.x, cloud.y, 0, cloud.x, cloud.y, cloud.size);
            gradient.addColorStop(0, cloud.color);
            gradient.addColorStop(1, 'transparent');
            
            ctx.beginPath();
            ctx.arc(cloud.x, cloud.y, cloud.size * (1 + Math.sin(time + cloud.x * 0.01) * 0.1), 0, Math.PI * 2);
            ctx.fillStyle = gradient;
            ctx.fill();
            
            cloud.x += cloud.speedX;
            cloud.y += cloud.speedY;
            
            if (cloud.x < -cloud.size) cloud.x = canvas.width + cloud.size;
            if (cloud.x > canvas.width + cloud.size) cloud.x = -cloud.size;
            if (cloud.y < -cloud.size) cloud.y = canvas.height + cloud.size;
            if (cloud.y > canvas.height + cloud.size) cloud.y = -cloud.size;
        });
        
        // 반짝이는 별
        stars.forEach(star => {
            star.twinkle += 0.05;
            ctx.beginPath();
            ctx.arc(star.x, star.y, star.size * (0.5 + Math.sin(star.twinkle) * 0.5), 0, Math.PI * 2);
            ctx.fillStyle = `rgba(0,255,255,${0.5 + Math.sin(star.twinkle) * 0.5})`;
            ctx.fill();
        });
        
        time += 0.015;
        requestAnimationFrame(draw);
    }
    draw();
    
    window.addEventListener('resize', () => {
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;
    });
})();
</script>

<?php elseif($theme == 24): /* 유성우 */ ?>
<div id="meteorContainer"></div>
<script>
(function() {
    const container = document.getElementById('meteorContainer');
    if (!container) return;
    
    const canvas = document.createElement('canvas');
    canvas.style.cssText = 'width:100%;height:100%;';
    container.appendChild(canvas);
    
    const ctx = canvas.getContext('2d');
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    
    const stars = [];
    for (let i = 0; i < 150; i++) {
        stars.push({
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height,
            size: Math.random() * 1.5,
            twinkle: Math.random() * Math.PI * 2
        });
    }
    
    const meteors = [];
    function createMeteor() {
        meteors.push({
            x: Math.random() * canvas.width * 1.5,
            y: -20,
            length: Math.random() * 100 + 50,
            speed: Math.random() * 12 + 8,
            angle: Math.PI / 4 + (Math.random() - 0.5) * 0.3
        });
    }
    
    function draw() {
        ctx.fillStyle = 'rgba(0,0,32,0.15)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        
        // 배경 별
        stars.forEach(star => {
            star.twinkle += 0.03;
            ctx.beginPath();
            ctx.arc(star.x, star.y, star.size * (0.5 + Math.sin(star.twinkle) * 0.5), 0, Math.PI * 2);
            ctx.fillStyle = '#fff';
            ctx.fill();
        });
        
        // 유성
        meteors.forEach((meteor, i) => {
            const gradient = ctx.createLinearGradient(
                meteor.x, meteor.y,
                meteor.x - Math.cos(meteor.angle) * meteor.length,
                meteor.y - Math.sin(meteor.angle) * meteor.length
            );
            gradient.addColorStop(0, 'rgba(255,215,0,1)');
            gradient.addColorStop(0.2, 'rgba(255,165,0,0.8)');
            gradient.addColorStop(1, 'rgba(255,215,0,0)');
            
            ctx.beginPath();
            ctx.moveTo(meteor.x, meteor.y);
            ctx.lineTo(
                meteor.x - Math.cos(meteor.angle) * meteor.length,
                meteor.y - Math.sin(meteor.angle) * meteor.length
            );
            ctx.strokeStyle = gradient;
            ctx.lineWidth = 2;
            ctx.stroke();
            
            // 유성 머리 빛
            ctx.beginPath();
            ctx.arc(meteor.x, meteor.y, 3, 0, Math.PI * 2);
            ctx.fillStyle = '#fff';
            ctx.fill();
            
            meteor.x += Math.cos(meteor.angle) * meteor.speed;
            meteor.y += Math.sin(meteor.angle) * meteor.speed;
            
            if (meteor.y > canvas.height + 100) {
                meteors.splice(i, 1);
            }
        });
        
        if (Math.random() < 0.02) createMeteor();
        requestAnimationFrame(draw);
    }
    draw();
    
    window.addEventListener('resize', () => {
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;
    });
})();
</script>

<?php elseif($theme == 25): /* 딥 스페이스 */ ?>
<div id="deepspaceContainer"></div>
<script>
(function() {
    const container = document.getElementById('deepspaceContainer');
    if (!container) return;
    
    const canvas = document.createElement('canvas');
    canvas.style.cssText = 'width:100%;height:100%;';
    container.appendChild(canvas);
    
    const ctx = canvas.getContext('2d');
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    
    const stars = [];
    for (let i = 0; i < 300; i++) {
        stars.push({
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height,
            z: Math.random() * canvas.width,
            size: Math.random() * 2
        });
    }
    
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    
    function draw() {
        ctx.fillStyle = 'rgba(0,0,0,0.1)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        
        stars.forEach(star => {
            star.z -= 3;
            if (star.z <= 0) {
                star.z = canvas.width;
                star.x = Math.random() * canvas.width;
                star.y = Math.random() * canvas.height;
            }
            
            const k = 200 / star.z;
            const px = (star.x - cx) * k + cx;
            const py = (star.y - cy) * k + cy;
            const size = (1 - star.z / canvas.width) * 4;
            const alpha = 1 - star.z / canvas.width;
            
            // 별 꼬리 (속도감)
            const tailLength = (1 - star.z / canvas.width) * 15;
            if (tailLength > 2) {
                const gradient = ctx.createLinearGradient(px, py, px - (px - cx) * 0.02, py - (py - cy) * 0.02);
                gradient.addColorStop(0, `rgba(0,150,255,${alpha})`);
                gradient.addColorStop(1, 'transparent');
                ctx.beginPath();
                ctx.moveTo(px, py);
                ctx.lineTo(px - (px - cx) * 0.05, py - (py - cy) * 0.05);
                ctx.strokeStyle = gradient;
                ctx.lineWidth = size;
                ctx.stroke();
            }
            
            ctx.beginPath();
            ctx.arc(px, py, size, 0, Math.PI * 2);
            ctx.fillStyle = `rgba(0,150,255,${alpha})`;
            ctx.fill();
        });
        
        requestAnimationFrame(draw);
    }
    draw();
    
    window.addEventListener('resize', () => {
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;
    });
})();
</script>

