        const pixel = document.createElement('div');
        const size = Math.random() * 6 + 4;
        pixel.style.cssText = `position:absolute;width:${size}px;height:${size}px;background:${colors[Math.floor(Math.random()*colors.length)]};left:${Math.random()*100}%;top:${Math.random()*100}%;animation:pixelBlink ${Math.random()*2+1}s step-end infinite;`;
        container.appendChild(pixel);
    }
    
    for (let i = 0; i < 20; i++) createPixel();
    
    const style = document.createElement('style');
    style.textContent = '@keyframes pixelBlink{0%,40%{opacity:1}41%,100%{opacity:0.2}}';
    document.head.appendChild(style);
})();
</script>

