<?php elseif($theme == 17): /* 골드 럭셔리 - 반짝이 효과 */ ?>
<div id="goldContainer" style="position:fixed;top:0;left:0;right:0;bottom:0;z-index:1;pointer-events:none;overflow:hidden;"></div>
<script>
(function() {
    const container = document.getElementById('goldContainer');
    if (!container) return;
    
    function createSparkle() {
        const sparkle = document.createElement('div');
        sparkle.textContent = '✦';
        sparkle.style.cssText = `position:absolute;left:${Math.random()*100}%;top:${Math.random()*100}%;font-size:${Math.random()*12+8}px;color:#ffd700;animation:goldSparkle 2s ease-out forwards;text-shadow:0 0 10px #ffd700;`;
        container.appendChild(sparkle);
        setTimeout(() => sparkle.remove(), 2000);
    }
    
    setInterval(createSparkle, 300);
    
    const style = document.createElement('style');
    style.textContent = '@keyframes goldSparkle{0%{transform:scale(0) rotate(0deg);opacity:1}100%{transform:scale(1.5) rotate(180deg);opacity:0}}';
    document.head.appendChild(style);
})();
</script>

